from opentelemetry import trace
import time


def record_streaming_milestones(span: trace.Span, model: str) -> None:
    """Add span events for key milestones in a streaming response."""

    # First token received — critical for TTFT (time to first token) SLO
    span.add_event(
        "gen_ai.first_token",
        attributes={
            "gen_ai.system": "openai",
            "gen_ai.request.model": model,
        }
    )

    # Tool call initiated by the model
    span.add_event(
        "gen_ai.tool_call",
        attributes={
            "gen_ai.tool.name": "web_search",
            "gen_ai.tool.call_id": "call_abc123",
        }
    )

    # Safety classifier decision (pass/block)
    span.add_event(
        "gen_ai.safety.decision",
        attributes={
            "gen_ai.safety.action": "pass",
            "gen_ai.safety.score": 0.02,
            "gen_ai.safety.model": "llama-guard-3",
            "gen_ai.safety.latency_ms": 38,
        }
    )

from dataclasses import dataclass
from typing import Any


REQUIRED_GENAI_ATTRIBUTES = {
    "gen_ai.system",
    "gen_ai.request.model",
    "gen_ai.usage.input_tokens",
    "gen_ai.usage.output_tokens",
}

RECOMMENDED_GENAI_ATTRIBUTES = {
    "gen_ai.response.model",
    "gen_ai.response.finish_reasons",
    "gen_ai.response.id",
    "gen_ai.request.max_tokens",
}


@dataclass
class ConventionCheckResult:
    missing_required: list[str]
    missing_recommended: list[str]

    @property
    def is_compliant(self) -> bool:
        return len(self.missing_required) == 0

    def report(self) -> str:
        lines = [f"Convention check: {'PASS' if self.is_compliant else 'FAIL'}"]
        if self.missing_required:
            lines.append(f"  MISSING required: {self.missing_required}")
        if self.missing_recommended:
            lines.append(f"  MISSING recommended: {self.missing_recommended}")
        return "\n".join(lines)


def check_genai_span(attributes: dict[str, Any]) -> ConventionCheckResult:
    missing_req = [a for a in REQUIRED_GENAI_ATTRIBUTES if a not in attributes]
    missing_rec = [a for a in RECOMMENDED_GENAI_ATTRIBUTES if a not in attributes]
    return ConventionCheckResult(missing_req, missing_rec)


# Example: use in a test that captures an exported span
def test_chat_span_conventions(exported_spans: list[dict]) -> None:
    chat_spans = [s for s in exported_spans if "gen_ai" in s.get("name", "")]
    assert chat_spans, "No gen_ai spans found — instrumentation missing"
    for span in chat_spans:
        result = check_genai_span(span.get("attributes", {}))
        assert result.is_compliant, result.report()
